#include "MyComponent.h"

#include "mozilla/ClearOnShutdown.h"
#include "mozilla/Logging.h"
#include "mozilla/RefPtr.h"
#include "mozilla/Components.h"
#include "mozilla/ModuleUtils.h"
#include "nsIObserverService.h"
#include "nsServiceManagerUtils.h"

namespace mozilla {

LazyLogModule gMyComponentLog("MyComponent");

StaticRefPtr<MyComponent> sMyComponentInstance;

// Implementation of nsIObserver::Observe method
NS_IMETHODIMP
MyComponent::Observe(nsISupports* aSubject, const char* aTopic,
                      const char16_t* aData) {
  MOZ_LOG(gMyComponentLog, LogLevel::Debug,
          ("MyComponent::Observe called with topic: %s", aTopic));
  return NS_OK;
}

// Implementation of reference counting and interface discovery
NS_IMPL_ISUPPORTS(MyComponent, nsIObserver)

// Component initialization
nsresult MyComponent::Init() {
  if (mIsInitialized) {
    return NS_OK;
  }

  MOZ_LOG(gMyComponentLog, LogLevel::Debug, ("MyComponent::Init called"));

  // Register as observer with the observer service
  nsCOMPtr<nsIObserverService> observerService =
      do_GetService("@mozilla.org/observer-service;1");
  if (!observerService) {
    return NS_ERROR_FAILURE;
  }

  nsresult rv = observerService->AddObserver(this, "profile-after-change", false);
  if (NS_FAILED(rv)) {
    return rv;
  }

  mIsInitialized = true;
  return NS_OK;
}

// Component shutdown
nsresult MyComponent::Shutdown() {
  if (!mIsInitialized) {
    return NS_OK;
  }

  MOZ_LOG(gMyComponentLog, LogLevel::Debug, ("MyComponent::Shutdown called"));

  // Unregister from observer service
  nsCOMPtr<nsIObserverService> observerService =
      do_GetService("@mozilla.org/observer-service;1");
  if (observerService) {
    observerService->RemoveObserver(this, "profile-after-change");
  }

  mIsInitialized = false;
  return NS_OK;
}

// Component factory constructor using the generic factory pattern
// This macro generates a constructor function that:
// 1. Creates a new instance of MyComponent
// 2. Calls QueryInterface to get the requested interface
// 3. Returns the interface to the caller
NS_GENERIC_FACTORY_CONSTRUCTOR_INIT(MyComponent, Init)

// Component registration using module utilities
// The NS_GENERIC_FACTORY_CONSTRUCTOR_INIT macro automatically
// generates a MyComponentConstructor function that is called
// by the component registry to create instances of this component.

}  // namespace mozilla

